// // This module captures the value of input D on the falling edge of the clock (CLK) when the enable signal (G) is low.
module top_module(
  input D, G, CLK,
  output Q
);reg Q_int;

  always @(posedge CLK) begin
    if (G) begin
      Q_int <= D;
    end
  end

  assign Q = Q_int;

endmodule
